import{_ as i,o as a,c as o,ae as t}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Google ICM","description":"","frontmatter":{"title":"Google ICM","slug":"google-icm"},"headers":[],"relativePath":"developer-hub/google-icm.md","filePath":"developer-hub/google-icm.md"}'),r={name:"developer-hub/google-icm.md"};function n(s,e,l,c,d,p){return a(),o("div",null,[...e[0]||(e[0]=[t('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>As an official Google <a href="https://support.google.com/google-ads/answer/12961402" target="_blank" rel="noreferrer">App Attribution Partner</a>, Branch supports ICM to empower marketers and developers with improved insights while prioritizing user privacy.</p><h2 id="what-is-google-icm" tabindex="-1">What is Google ICM? <a class="header-anchor" href="#what-is-google-icm" aria-label="Permalink to &quot;What is Google ICM?&quot;">​</a></h2><p>Google&#39;s ICM is a forward-thinking solution designed to provide more reliable and privacy-centric mobile app conversion measurement.</p><p>By leveraging techniques like <a href="https://support.google.com/google-ads/answer/12119136" target="_blank" rel="noreferrer">on-device measurement</a>, ICM aims to improve reporting accuracy for iOS and Android campaigns, especially in light of evolving privacy landscapes.</p><p>On-device measurement is a privacy-preserving technique where conversion data is processed directly on the user&#39;s device rather than being sent to a centralized server for aggregation before attribution. This method enhances user privacy while still allowing for accurate campaign measurement.</p><h2 id="key-benefits" tabindex="-1">Key benefits <a class="header-anchor" href="#key-benefits" aria-label="Permalink to &quot;Key benefits&quot;">​</a></h2><p>Below are some of the key benefits you can expect from using Google’s ICM with Branch:</p><ul><li><p><strong>Enhanced reporting across iOS &amp; Android</strong>: Get real-time and event-level reporting of your campaign performance.</p><ul><li>On iOS, gain improved reporting for app conversions from iOS 14+ users.</li><li>On Android, benefit from better reporting for app conversions from the European Economic Area (EEA) or when a user opts out of device-level permissions.</li></ul></li><li><p><strong>Privacy-preserving techniques</strong>: ICM utilizes privacy-preserving technologies, ensuring no identifiable information leaves a user&#39;s device or is disclosed externally, including to Google.</p></li><li><p><strong>Seamless integration</strong>: As a Google App Attribution Partner, Branch directly integrates with Google ICM, enhancing reporting for advertisers whether you&#39;re using our SDK or server-to-server integrations.</p></li></ul><h2 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h2><p>Use the information in this section to understand the process for getting Google ICM data flowing for your app campaigns.</p><h3 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h3><p>To enable enhanced reporting for your iOS app campaigns with Google ICM through Branch, follow the steps below.</p><h4 id="all-integrations" tabindex="-1">All integrations <a class="header-anchor" href="#all-integrations" aria-label="Permalink to &quot;All integrations&quot;">​</a></h4><p>For both automatic and manual integrations, you need to:</p><ol><li><p>Confirm that you have an active iOS App campaign for installs with Google Ads</p></li><li><p>Upgrade to <a href="https://github.com/BranchMetrics/ios-branch-deep-linking-attribution/releases" target="_blank" rel="noreferrer">Branch iOS SDK (v3.13.3 or higher)</a></p><ol><li>Use the Branch iOS SDK’s <code>setSDKWaitTimeForThirdPartyAPIs</code> <a href="https://help.branch.io/developers-hub/docs/ios-full-reference#setsdkwaittimeforthirdpartyapis" target="_blank" rel="noreferrer">method</a>, and set the <code>waitTime</code> to at least 5 seconds.</li></ol></li><li><p>Use this <a href="https://firebase.google.com/docs/tutorials/ads-ios-on-device-measurement-event-data/step-2" target="_blank" rel="noreferrer">Firebase tutorial</a> to link your app to the <code>GoogleAdsOnDeviceConversion</code> framework using one of the following methods:</p><ol><li>CocoaPods</li><li>Swift Package Manager</li><li>A manual integration using a downloaded version of the Firebase iOS SDK</li></ol></li><li><p>In Xcode, add the <code>-ObjC</code> flag to <strong>Other Linker Settings</strong> in your app target&#39;s build settings.</p><ol><li>Please note that you must do this regardless of what method you used to integrate the <code>GoogleAdsOnDeviceConversion</code> framework.</li></ol></li></ol><p>At this point, you are fully set up to have Branch automatically fetch ODM info. No additional code is required. Branch will automatically handle ODM data fetching and reporting.</p><h4 id="manual-integrations" tabindex="-1">Manual integrations <a class="header-anchor" href="#manual-integrations" aria-label="Permalink to &quot;Manual integrations&quot;">​</a></h4><p>If you want custom control over ODM data fetching, you can implement a manual integration.</p><ol><li>First, complete all steps outlined in the “<a href="./google-icm.html#all-integrations">All integrations</a>” section.</li><li>Fetch ODM info using Google’s <code>GoogleAdsOnDeviceConversion</code> API, specifically the <code>fetchAggregateConversionInfoForInteraction</code> method.</li><li>Pass this ODM info to Branch using the Branch iOS SDK’s <code>setODMInfo</code> method:</li></ol><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-hUzni" id="tab--xxEbI6" checked><label data-title="Swift" for="tab--xxEbI6">Swift</label><input type="radio" name="group-hUzni" id="tab-RDHLgzP"><label data-title="Objective-C" for="tab-RDHLgzP">Objective-C</label></div><div class="blocks"><div class="language-swift vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">swift</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Branch.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">setODMInfo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(odmInfo, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">andFirstOpenTimestamp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: firstLaunchTime)</span></span></code></pre></div><div class="language-objectivec vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">objectivec</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Branch setODMInfo:aggregateConversionInfo andFirstOpenTimestamp:firstLaunchTime];</span></span></code></pre></div></div></div><p>To learn more about this method, visit our <a href="https://help.branch.io/developers-hub/docs/ios-full-reference#setodminfo" target="_blank" rel="noreferrer">iOS Full Reference</a> guide.</p><h3 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h3><p>There are no actions that you need to take in order to gain access to this solution for Android. Measurement improvements will automatically be applied as available.</p><h2 id="additional-resources" tabindex="-1">Additional resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional resources&quot;">​</a></h2><p>For more information about Google’s requirements for ICM, please refer to Google’s <a href="https://support.google.com/google-ads/answer/12119136?sjid=7730411304741579192-NC#:~:text=Implementation%20requirements%20to%20get%20started" target="_blank" rel="noreferrer">Integration Guide</a> and to your Google representative.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>To analyze cross-channel attribution, considering coupling ICM with Branch’s <a href="./predictive-aggregate-measurement.html">Predictive Aggregate Measurement (PAM)</a>. While ICM improves visibility into conversions under privacy constraints, PAM complements this by providing insights into previously unattributed conversions, offering a more comprehensive view of campaign performance.</p></div>',27)])])}const u=i(r,[["render",n]]);export{g as __pageData,u as default};
